// Generated by Trae Work
(function() {
  var style = getComputedStyle(document.documentElement);
  var accent = style.getPropertyValue('--accent').trim();
  var accent2 = style.getPropertyValue('--accent2').trim();
  var ink = style.getPropertyValue('--ink').trim();
  var muted = style.getPropertyValue('--muted').trim();
  var rule = style.getPropertyValue('--rule').trim();
  var bg2 = style.getPropertyValue('--bg2').trim();
  var warn = style.getPropertyValue('--warn').trim();
  var danger = style.getPropertyValue('--danger').trim();

  // --- Chart: Maturity Bar Chart ---
  var barEl = document.getElementById('chart-maturity-bar');
  if (barEl) {
    var barChart = echarts.init(barEl, null, { renderer: 'svg' });
    var categories = [
      '核心流程确定性',
      '沙箱安全隔离',
      '降级与容错策略',
      '可观测性',
      'RAG检索系统',
      '浏览器自动化',
      '后端测试覆盖',
      '记忆与持久化',
      '认证与安全',
      'RAG质量评估',
      '前端测试覆盖'
    ];
    var scores = [8.5, 8.5, 8.0, 7.5, 6.5, 6.0, 5.5, 4.0, 3.0, 1.5, 0.0];

    // Color function: green for >=7, yellow for 4-7, red for <4
    function barColor(v) {
      if (v >= 7.0) return accent2;
      if (v >= 4.0) return warn;
      return danger;
    }

    barChart.setOption({
      animation: false,
      tooltip: {
        trigger: 'axis',
        axisPointer: { type: 'shadow' },
        appendToBody: true,
        formatter: function(params) {
          var v = params[0].value;
          var level = v >= 7 ? '优秀' : v >= 4 ? '及格' : '不足';
          return params[0].name + '<br/>评分: <strong>' + v.toFixed(1) + '</strong> / 10 (' + level + ')';
        }
      },
      grid: { left: 140, right: 60, top: 10, bottom: 10 },
      xAxis: {
        type: 'value',
        min: 0,
        max: 10,
        axisLabel: { color: muted, fontSize: 11, fontFamily: 'JetBrainsMono, monospace' },
        axisLine: { lineStyle: { color: rule } },
        splitLine: { lineStyle: { color: rule } },
        name: '评分 (0-10)',
        nameTextStyle: { color: muted, fontSize: 11 }
      },
      yAxis: {
        type: 'category',
        data: categories.reverse(),
        axisLabel: { color: ink, fontSize: 12, fontFamily: 'WorkSans, sans-serif' },
        axisLine: { lineStyle: { color: rule } },
        axisTick: { show: false },
        inverse: true
      },
      series: [{
        type: 'bar',
        data: scores.reverse().map(function(v) {
          return {
            value: v,
            itemStyle: {
              color: barColor(v),
              borderRadius: [0, 4, 4, 0]
            }
          };
        }),
        barWidth: 18,
        label: {
          show: true,
          position: 'right',
          color: muted,
          fontSize: 11,
          fontFamily: 'JetBrainsMono, monospace',
          formatter: function(p) { return p.value.toFixed(1); }
        }
      }]
    });
    window.addEventListener('resize', function() { barChart.resize(); });
  }

  // --- Chart: Maturity Radar Chart ---
  var radarEl = document.getElementById('chart-maturity-radar');
  if (radarEl) {
    var radarChart = echarts.init(radarEl, null, { renderer: 'svg' });
    radarChart.setOption({
      animation: false,
      tooltip: {
        appendToBody: true,
        formatter: function(params) {
          return params.name + ': <strong>' + params.value.toFixed(1) + '</strong> / 10';
        }
      },
      legend: {
        data: ['当前成熟度'],
        bottom: 0,
        textStyle: { color: ink, fontSize: 12, fontFamily: 'WorkSans, sans-serif' }
      },
      radar: {
        center: ['50%', '52%'],
        radius: '68%',
        indicator: [
          { name: '核心流程\n确定性', max: 10 },
          { name: '沙箱安全\n隔离', max: 10 },
          { name: '降级与\n容错策略', max: 10 },
          { name: '可观测性', max: 10 },
          { name: 'RAG\n检索系统', max: 10 },
          { name: '浏览器\n自动化', max: 10 },
          { name: '后端测试\n覆盖', max: 10 },
          { name: '记忆与\n持久化', max: 10 },
          { name: '认证与\n安全', max: 10 },
          { name: 'RAG质量\n评估', max: 10 },
          { name: '前端测试\n覆盖', max: 10 }
        ],
        axisName: {
          color: ink,
          fontSize: 11,
          fontFamily: 'WorkSans, sans-serif'
        },
        splitArea: {
          areaStyle: { color: [bg2, bg2] }
        },
        splitLine: {
          lineStyle: { color: rule }
        },
        axisLine: {
          lineStyle: { color: rule }
        }
      },
      series: [{
        type: 'radar',
        name: '当前成熟度',
        data: [{
          value: [8.5, 8.5, 8.0, 7.5, 6.5, 6.0, 5.5, 4.0, 3.0, 1.5, 0.0],
          name: '当前成熟度',
          areaStyle: { color: accent + '22' },
          lineStyle: { color: accent, width: 2 },
          itemStyle: { color: accent },
          symbol: 'circle',
          symbolSize: 6
        }]
      }]
    });
    window.addEventListener('resize', function() { radarChart.resize(); });
  }
})();